{!REQUIRESCRIPT("/soap/ajax/30.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/30.0/apex.js")}

var contractId = '{!Site__c.ContractId__c}';
var sitId = '{!Site__c.Id}';
var siteStatus = '{!Site__c.Site_Status__c}';
var invoiceResult;
console.log("SiteStatus");
console.log(siteStatus);
if (siteStatus !== null && siteStatus == 'Closed') {
    if (sitId !== null && contractId !== null) {
        invoiceResult = sforce.apex.execute("GenerateInvoice", "generateInvoiceRecord", {
            contId: contractId,
            siteId: sitId
        });

        if (invoiceResult[0].length == 18) {
            alert("You have successfully generated an Invoice");
            window.location = '/' + invoiceResult;
        } else {
            alert(invoiceResult);
        }
    }
} else {
    alert("Cannot Generate an Invoice for a Site that is not Closed.");
}
